import React, { useState } from 'react';
import { Star, Clock, Users, Play, Heart, Share2, TrendingUp, Award, BookOpen } from 'lucide-react';
import { useIntersectionObserver } from '../hooks/useIntersectionObserver';
import useCourseStore from '../store/courseStore';

const CourseCard = ({ course, viewMode = 'grid', onEnroll, onPreview }) => {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);
  const { elementRef, hasIntersected } = useIntersectionObserver();

  const { favorites, toggleFavorite, enrolledCourses } = useCourseStore();

  const isEnrolled = enrolledCourses.includes(course.id);
  const isFavorite = favorites.includes(course.id);
  const isPopular = course.enrolled > 1000;
  const isHighRated = parseFloat(course.rating) >= 4.5;

  const handleImageLoad = () => setImageLoaded(true);
  const handleImageError = () => setImageError(true);

  const handleFavoriteClick = (e) => {
    e.stopPropagation();
    toggleFavorite(course.id);
  };

  const handleShareClick = (e) => {
    e.stopPropagation();
    if (navigator.share) {
      navigator.share({
        title: course.title,
        text: course.desc,
        url: window.location.href
      });
    } else {
      navigator.clipboard.writeText(window.location.href);
    }
  };

  const getLevelColor = (level) => {
    switch (level) {
      case 'Beginner':
        return 'bg-green-100 text-green-700 border-green-200';
      case 'Intermediate':
        return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case 'Advanced':
        return 'bg-red-100 text-red-700 border-red-200';
      default:
        return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const cardClasses = `
    bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-200 
    hover:shadow-xl hover:-translate-y-1 transition-all duration-300 
    group cursor-pointer
    ${viewMode === 'list' ? 'flex' : ''}
  `;

  const imageClasses = `
    relative overflow-hidden
    ${viewMode === 'list' ? 'w-48 h-32 flex-shrink-0' : 'h-48'}
  `;

  return (
    <div ref={elementRef} className={cardClasses} onClick={() => onPreview?.(course)}>
      {/* Image Section */}
      <div className={imageClasses}>
        {hasIntersected && (
          <>
            {!imageError ? (
              <img 
                src={course.img} 
                alt={course.title}
                className={`w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 ${
                  imageLoaded ? 'opacity-100' : 'opacity-0'
                }`}
                onLoad={handleImageLoad}
                onError={handleImageError}
                loading="lazy"
              />
            ) : (
              <div className="w-full h-full bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center">
                <BookOpen className="w-12 h-12 text-gray-400" />
              </div>
            )}
          </>
        )}

        {/* Image Overlay */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

        {/* Badges */}
        <div className="absolute top-3 left-3 flex flex-col space-y-2">
          {course.progress > 0 && (
            <div className="bg-gradient-to-r from-green-500 to-green-600 text-white px-3 py-1 rounded-full text-xs font-semibold shadow-lg">
              {course.progress}% Complete
            </div>
          )}
          {isEnrolled && (
            <div className="bg-blue-500 text-white px-3 py-1 rounded-full text-xs font-semibold shadow-lg">
              Enrolled
            </div>
          )}
          {isPopular && (
            <div className="bg-orange-500 text-white px-3 py-1 rounded-full text-xs font-semibold shadow-lg flex items-center">
              <TrendingUp className="w-3 h-3 mr-1" />
              Popular
            </div>
          )}
          {isHighRated && (
            <div className="bg-yellow-500 text-white px-3 py-1 rounded-full text-xs font-semibold shadow-lg flex items-center">
              <Award className="w-3 h-3 mr-1" />
              Top Rated
            </div>
          )}
        </div>

        {/* Action Buttons */}
        <div className="absolute top-3 right-3 flex space-x-2">
          <div className="bg-black/70 backdrop-blur-sm text-white px-2 py-1 rounded-full text-xs flex items-center">
            <Star className="w-3 h-3 mr-1 fill-yellow-400 text-yellow-400" />
            {course.rating}
          </div>
          <button
            onClick={handleFavoriteClick}
            className={`p-2 rounded-full backdrop-blur-sm transition-all duration-200 ${
              isFavorite 
                ? 'bg-red-500 text-white' 
                : 'bg-white/20 text-white hover:bg-white/30'
            }`}
            aria-label={isFavorite ? 'Remove from favorites' : 'Add to favorites'}
          >
            <Heart className={`w-4 h-4 ${isFavorite ? 'fill-current' : ''}`} />
          </button>
        </div>

        {/* Hover Actions */}
        <div className="absolute bottom-3 left-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div className="flex space-x-2">
            <button 
              onClick={(e) => {
                e.stopPropagation();
                onPreview?.(course);
              }}
              className="flex-1 bg-white/90 backdrop-blur-sm text-gray-900 px-3 py-2 rounded-lg text-xs font-medium hover:bg-white transition-colors"
            >
              <Play className="w-3 h-3 inline mr-1" />
              Preview
            </button>
            <button 
              onClick={handleShareClick}
              className="bg-white/20 backdrop-blur-sm text-white p-2 rounded-lg hover:bg-white/30 transition-colors"
              aria-label="Share course"
            >
              <Share2 className="w-3 h-3" />
            </button>
          </div>
        </div>
      </div>

      {/* Content Section */}
      <div className={`p-4 ${viewMode === 'list' ? 'flex-1' : ''}`}>
        <div className="flex items-start justify-between mb-3">
          <h3 className="text-lg font-bold text-gray-900 group-hover:text-blue-600 transition-colors line-clamp-2">
            {course.title}
          </h3>
        </div>

        <p className="text-gray-600 text-sm mb-4 line-clamp-2 leading-relaxed">
          {course.desc}
        </p>

        {/* Course Meta */}
        <div className="flex items-center justify-between mb-4 text-xs text-gray-500 flex-wrap gap-2">
          <div className="flex items-center space-x-3">
            <span className={`px-3 py-1 rounded-full font-medium border ${getLevelColor(course.level)}`}>
              {course.level}
            </span>
            <span className="flex items-center">
              <Clock className="w-3 h-3 mr-1" />
              {course.time}
            </span>
            <span className="flex items-center">
              <Users className="w-3 h-3 mr-1" />
              {course.enrolled?.toLocaleString() || 0}
            </span>
          </div>
        </div>

        {/* Progress Bar */}
        {course.progress > 0 && (
          <div className="mb-4">
            <div className="flex justify-between text-xs text-gray-600 mb-1">
              <span>Progress</span>
              <span>{course.progress}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div 
                className="bg-gradient-to-r from-blue-500 to-purple-500 h-2 rounded-full transition-all duration-300"
                style={{ width: `${course.progress}%` }}
              />
            </div>
          </div>
        )}

        {/* Footer */}
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
          <div>
            <div className="text-sm text-gray-600 mb-1">{course.instructor}</div>
            <div className="text-xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              ₹{course.price?.toLocaleString() || 0}
            </div>
          </div>

          {isEnrolled ? (
            <button 
              onClick={(e) => {
                e.stopPropagation();
                alert('🎉 Welcome to your course! Course content will be available here.');
              }}
              className="w-full sm:w-auto bg-green-500 hover:bg-green-600 text-white px-6 py-3 rounded-xl text-sm font-semibold transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-xl"
            >
              ▶ Try Course
            </button>
          ) : (
            <button 
              onClick={(e) => {
                e.stopPropagation();
                onEnroll?.(course);
              }}
              className="w-full sm:w-auto bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white px-6 py-3 rounded-xl text-sm font-semibold transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-xl"
            >
              Enroll Now
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default CourseCard;
